# Configuration from environment variables
STORAGE_ACCOUNT_URL = os.environ.get("STORAGE_ACCOUNT_URL")
COSMOS_ENDPOINT = os.environ.get("COSMOS_ENDPOINT")
COSMOS_DATABASE = os.environ.get("COSMOS_DATABASE", "processing-db")
COSMOS_CONTAINER = os.environ.get("COSMOS_CONTAINER", "results")
EVENTGRID_TOPIC_ENDPOINT = os.environ.get("EVENTGRID_TOPIC_ENDPOINT")
ALLOWED_CONTAINER = os.environ.get("ALLOWED_BLOB_CONTAINER", "input-files")
MAX_BLOB_SIZE_BYTES = int(os.environ.get("MAX_BLOB_SIZE_BYTES", str(10 * 1024 * 1024)))  # 10MB default
ALLOWED_CONTENT_TYPES = {"application/json", "text/csv", "text/plain"}

app = func.FunctionApp()


def _get_credential():
    """
    Return a ManagedIdentityCredential for production use.
    DefaultAzureCredential is avoided in production to prevent
    fallback to developer credentials or environment variables
    that could be manipulated.
    """
    managed_identity_client_id = os.environ.get("MANAGED_IDENTITY_CLIENT_ID")
    if managed_identity_client_id:
        return ManagedIdentityCredential(client_id=managed_identity_client_id)
    # In production, a user-assigned managed identity with explicit client_id is preferred.
    # System-assigned is acceptable but less portable.
    return ManagedIdentityCredential()


def _get_blob_service_client(credential):
    """
    Create a BlobServiceClient with read-only intent.
    The managed identity should only have Storage Blob Data Reader
    on the specific input container.
    """
    if not STORAGE_ACCOUNT_URL:
        raise ValueError("STORAGE_ACCOUNT_URL is not configured")
    return BlobServiceClient(account_url=STORAGE_ACCOUNT_URL, credential=credential)


def _get_cosmos_client(credential):
    """
    Create a CosmosClient using AAD authentication (data plane RBAC).
    The managed identity should have 'Cosmos DB Built-in Data Contributor'
    role assigned at the database or container level — NOT the control plane
    'Cosmos DB Account Contributor' role.
    """
    if not COSMOS_ENDPOINT:
        raise ValueError("COSMOS_ENDPOINT is not configured")
    return CosmosClient(url=COSMOS_ENDPOINT, credential=credential)


def _get_eventgrid_client(credential):
    """
    Create an EventGridPublisherClient using managed identity.
    The identity should have 'Event Grid Data Sender' role on the
    specific topic resource only.
    """
    if not EVENTGRID_TOPIC_ENDPOINT:
        raise ValueError("EVENTGRID_TOPIC_ENDPOINT is not configured")
    return EventGridPublisherClient(
        endpoint=EVENTGRID_TOPIC_ENDPOINT,
        credential=credential
    )


def _validate_blob_metadata(container_name: str, blob_name: str, blob_size: int, content_type: str) -> list:
    """
    Validate blob metadata before processing.
    Returns a list of validation errors (empty if valid).
    """
    errors = []

    # Validate container is the expected input container
    if container_name != ALLOWED_CONTAINER:
        errors.append(f"Blob is not in the allowed container '{ALLOWED_CONTAINER}'")

    # Validate blob name doesn't contain path traversal
    if ".." in blob_name or blob_name.startswith("/"):
        errors.append("Invalid blob name detected")

    # Validate size
    if blob_size > MAX_BLOB_SIZE_BYTES:
        errors.append(f"Blob size {blob_size} exceeds maximum {MAX_BLOB_SIZE_BYTES}")

    # Validate content type
    if content_type and content_type not in ALLOWED_CONTENT_TYPES:
        errors.append(f"Content type '{content_type}' is not allowed")

    return errors


def _sanitize_blob_content(content: bytes, content_type: str) -> dict:
    """
    Parse and validate blob content based on content type.
    Returns a sanitized dictionary representation.
    """
    if content_type == "application/json":
        try:
            parsed = json.loads(content.decode("utf-8"))
            if not isinstance(parsed, (dict, list)):
                raise ValueError("JSON root must be an object or array")
            return {"type": "json", "data": parsed}
        except (json.JSONDecodeError, UnicodeDecodeError) as e:
            raise ValueError(f"Invalid JSON content: {str(e)}")

    elif content_type in ("text/csv", "text/plain"):
        try:
            text = content.decode("utf-8")
            # Basic sanitization: limit line count
            lines = text.splitlines()
            if len(lines) > 100000:
                raise ValueError("File has too many lines")
            return {"type": "text", "line_count": len(lines), "preview": lines[:5]}
        except UnicodeDecodeError:
            raise ValueError("Invalid text encoding")

    else:
        return {"type": "binary", "size": len(content)}


def _build_cosmos_document(blob_name: str, container_name: str, processing_result: dict) -> dict:
    """
    Build a Cosmos DB document with a deterministic ID to prevent duplicates.
    """
    doc_id = str(uuid.uuid5(uuid.NAMESPACE_URL, f"{container_name}/{blob_name}"))
    return {
        "id": doc_id,
        "partitionKey": container_name,
        "blobName": blob_name,
        "containerName": container_name,
        "processedAt": datetime.now(timezone.utc).isoformat(),
        "result": processing_result,
        "status": "processed"
    }


def _build_event(blob_name: str, container_name: str, document_id: str) -> dict:
    """
    Build an Event Grid event for notification.
    Avoids including sensitive data in the event payload.
    """
    return {
        "id": str(uuid.uuid4()),
        "subject": f"processing/complete/{container_name}/{blob_name}",
        "data": {
            "blobName": blob_name,
            "containerName": container_name,
            "cosmosDocumentId": document_id,
            "processedAt": datetime.now(timezone.utc).isoformat(),
            # NOTE: Do not include blob content or processing details in events.
            # Consumers should query Cosmos DB for full results.
        },
        "eventType": "BlobProcessing.Completed",
        "dataVersion": "1.0",
        "eventTime": datetime.now(timezone.utc).isoformat()
    }


@app.blob_trigger(
    arg_name="inputblob",
    path=f"{os.environ.get('ALLOWED_BLOB_CONTAINER', 'input-files')}/{{name}}",
    connection="AzureWebJobsStorage"
)
def process_blob(inputblob: func.InputStream):
    """
    Azure Function triggered by new blobs in the input container.

    Security controls:
    - Managed Identity with least-privilege roles
    - Input validation (size, type, container)
    - Content sanitization
    - Deterministic document IDs (idempotency)
    - No sensitive data in Event Grid notifications
    - Structured error handling without information leakage
    """
    logging.info(f"Processing blob: {inputblob.name}, size: {inputblob.length}")

    try:
        # Extract metadata
        blob_path_parts = inputblob.name.split("/", 1) if inputblob.name else ["", ""]
        container_name = blob_path_parts[0] if len(blob_path_parts) > 1 else ALLOWED_CONTAINER
        blob_name = blob_path_parts[1] if len(blob_path_parts) > 1 else blob_path_parts[0]

        # Determine content type from blob properties or name
        content_type = getattr(inputblob, 'content_type', None) or ""
        if not content_type:
            if blob_name.endswith(".json"):
                content_type = "application/json"
            elif blob_name.endswith(".csv"):
                content_type = "text/csv"
            elif blob_name.endswith(".txt"):
                content_type = "text/plain"

        # Step 1: Validate blob metadata
        validation_errors = _validate_blob_metadata(
            container_name=container_name,
            blob_name=blob_name,
            blob_size=inputblob.length or 0,
            content_type=content_type
        )

        if validation_errors:
            logging.warning(
                f"Blob validation failed for '{blob_name}': {'; '.join(validation_errors)}"
            )
            return

        # Step 2: Read and validate content
        raw_content = inputblob.read()

        if len(raw_content) > MAX_BLOB_SIZE_BYTES:
            logging.warning(f"Blob content exceeds size limit after read: {len(raw_content)}")
            return

        processing_result = _sanitize_blob_content(raw_content, content_type)
        logging.info(f"Successfully parsed blob content as {processing_result['type']}")

        # Step 3: Get credential (Managed Identity)
        credential = _get_credential()

        # Step 4: Write results to Cosmos DB
        cosmos_client = _get_cosmos_client(credential)
        database = cosmos_client.get_database_client(COSMOS_DATABASE)
        container = database.get_container_client(COSMOS_CONTAINER)

        document = _build_cosmos_document(blob_name, container_name, processing_result)
        container.upsert_item(document)
        logging.info(f"Wrote document {document['id']} to Cosmos DB")

        # Step 5: Send notification via Event Grid
        eventgrid_client = _get_eventgrid_client(credential)
        event = _build_event(blob_name, container_name, document["id"])
        eventgrid_client.send([event])
        logging.info(f"Sent Event Grid notification for blob '{blob_name}'")

    except ValueError as ve:
        # Validation/parsing errors — log details internally, don't propagate
        logging.error(f"Validation error processing blob: {str(ve)}")

    except Exception as e:
        # Unexpected errors — log for debugging but don't leak details
        logging.error(f"Unexpected error processing blob '{inputblob.name}': {type(e).__name__}")
        logging.debug(f"Error details: {str(e)}")
        raise


@app.route(route="health", methods=["GET"], auth_level=func.AuthLevel.FUNCTION)
def health_check(req: func.HttpRequest) -> func.HttpResponse:
    """
    Health check endpoint.
    Uses FUNCTION auth level to require a function key.
    Does not expose internal configuration details.
    """
    health_status = {
        "status": "healthy",
        "timestamp": datetime.now(timezone.utc).isoformat(),
        "checks": {
            "storage_configured": bool(STORAGE_ACCOUNT_URL),
            "cosmos_configured": bool(COSMOS_ENDPOINT),
            "eventgrid_configured": bool(EVENTGRID_TOPIC_ENDPOINT),
        }
    }

    all_configured = all(health_status["checks"].values())
    status_code = 200 if all_configured else 503

    return func.HttpResponse(
        json.dumps(health_status),
        status_code=status_code,
        mimetype="application/json"
    )


